function getKey(env, clientId) { return (clientId && CUSTOMER_KEYS[clientId]) ? CUSTOMER_KEYS[clientId] : (env.FLEETAI_API_KEY || FALLBACK_KEY); }
function getClientMeta(clientId) { return CUSTOMER_META[clientId] || { company: COMPANY, location: LOCATION }; }

const CORS = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization, x-api-key",
};

function corsResponse(body, status = 200) {
  return new Response(body, { status, headers: { "Content-Type": "application/json", ...CORS } });
}
function errorResponse(msg, status = 500) {
  return corsResponse(JSON.stringify({ error: msg }), status);
}

// UBI API — vehicle list
async function ubiGET(path, env, key) {
  const res = await fetch(UBI_BASE + path, {
    method: "GET",
    headers: { "x-api-key": key || getKey(env), "Accept": "application/json" },
  });
  const text = await res.text();
  if (!res.ok) throw new Error("UBI " + res.status + ": " + text.slice(0, 200));
  return JSON.parse(text);
}

// FleetAI API — trip/driver performance data
async function netstarGET(path, env, key) {
  const res = await fetch(NETSTAR_BASE + path, {
    method: "GET",
    headers: { "x-api-key": key || getKey(env), "Accept": "application/json" },
  });
  const text = await res.text();
  if (!res.ok) throw new Error("FleetAI " + res.status + ": " + text.slice(0, 200));
  return JSON.parse(text);
}

// Get vehicle list from UBI API
async function getVehicleList(env, key, companyName) {
  let list = [];
  let branches = [];

  try {
    const res = await fetch(NETSTAR_BASE + "/external/company-vehicles", {
      method: "POST",
      headers: { "x-api-key": key || getKey(env), "Content-Type": "application/json", "Accept": "*/*" },
      body: JSON.stringify({ company_name: companyName || "", company_names: companyName ? [companyName] : [] }),
    });
    if (res.ok) {
      const data = await res.json();
      if (data?.data?.branch && Array.isArray(data.data.branch)) {
        for (const branch of data.data.branch) {
          if (branch.branch_name) branches.push(branch.branch_name);
          if (Array.isArray(branch.vehicles)) {
            for (const v of branch.vehicles) {
              list.push({ ...v, _branch: branch.branch_name });
            }
          }
        }
      } else {
        const flat = Array.isArray(data) ? data :
          Array.isArray(data?.data) ? data.data :
          Array.isArray(data?.vehicles) ? data.vehicles :
          Array.isArray(data?.result) ? data.result : [];
        list = flat;
      }
    }
  } catch(e) {}

  // Fallback to UBI endpoint for demo account
  if (list.length === 0) {
    try {
      const data = await ubiGET("/vehicle/vehicles", env, key);
      list = Array.isArray(data) ? data : (data.data || []);
    } catch(e) {}
  }

  const mapped = mapVehicles(list);
  // Attach branch list to result for use by getDriverPerf
  mapped._branches = branches;
  return mapped;
}

const DISPOSED_PATTERN = /dispose|disposal|disposed|spare|workshop|not working|breakdown|decommission/i;

function mapVehicles(list) {
  return list.filter(v => v && !v._debug).map(v => {
    const imei = String(v.imei_no || v.Imei || v.imei || v.IMEI || v.device_id || "");
    const vehicleNo = v.vehicle_no || v.device_name || "";
    const regMatch = vehicleNo.match(/^([A-Z0-9]+)/);
    const registration = v.Registration || v.registration || v.PlateNumber || v.plate_number || (regMatch ? regMatch[1] : vehicleNo) || imei;
    const driverFromVehicleNo = vehicleNo.includes(" ") ? vehicleNo.replace(/^\S+\s+/, "") : "";
    const driverRaw = v.DriverName || v.driver_name || v.Driver || v.driver || driverFromVehicleNo || "";
    // Flag disposed/spare/workshop vehicles
    const isDisposed = DISPOSED_PATTERN.test(driverRaw) || DISPOSED_PATTERN.test(registration);
    return {
      imei,
      id: imei,
      registration,
      make: v.Make || v.make || v.Brand || v.brand || v.device_model || "—",
      model: v.Model || v.model || "—",
      year: v.Year || v.year || null,
      driver_name: isDisposed ? "— Disposed / Spare" : (driverRaw || "—"),
      gvm_kg: parseFloat(v.GvmKg || v.gvm_kg || v.Gvm || v.gvm || 0) || 0,
      fuel_type: (v.FuelType || v.fuel_type || "diesel").toLowerCase(),
      branch: v._branch || "",
      _disposed: isDisposed,
    };
  }).filter(v => !v._disposed); // Remove disposed vehicles from fleet
}

// Convert yyyy-MM-dd to dd-MM-yyyy HH:mm:ss as required by FleetAI API
function toFleetAIDate(isoDate, endOfDay = false) {
  const [y, m, d] = isoDate.split("-");
  return `${d}-${m}-${y} ${endOfDay ? "23:59:59" : "00:00:01"}`;
}

// Get driver performance for a SINGLE 10-day window — chunking handled by frontend
async function getDriverPerf(dateFrom, dateTo, env, key, companyName, branches) {
  const q = new URLSearchParams({
    company_names: companyName || COMPANY,
    start_date_time: toFleetAIDate(dateFrom, false),
    end_date_time: toFleetAIDate(dateTo, true),
  });
  const locationNames = (branches && branches.length > 0) ? branches : [LOCATION];
  try {
    const branchResults = await Promise.all(locationNames.map(async loc => {
      const qWithLoc = new URLSearchParams(q);
      qWithLoc.set("location_names", loc);
      try {
        const data = await netstarGET("/external/drivers/driver-performance-summary?" + qWithLoc.toString(), env, key);
        return Array.isArray(data) ? data : Array.isArray(data?.data) ? data.data : (data.result || []);
      } catch(e) { return []; }
    }));
    const chunkData = branchResults.flat();
    const byDriver = {};
    for (const r of chunkData) {
      const raw = r.driver_name || r.DriverName || "";
      const clean = raw.replace(/^\d+\s+/, "").trim();
      const dKey = clean.toLowerCase();
      if (!dKey) continue;
      const km = parseFloat(r.total_running_km || 0);
      if (!byDriver[dKey] || km > parseFloat(byDriver[dKey].total_running_km || 0)) {
        byDriver[dKey] = { ...r, driver_name: clean, _raw_driver_name: raw };
      }
    }
    return Object.values(byDriver);
  } catch(e) { return []; }
}


// Get object status (odometer, fuel, speed) by IMEI
async function getObjectStatus(imei, env, key) {
  const data = await netstarGET("/external/reports/object-status?imei=" + imei, env);
  const list = Array.isArray(data) ? data : (data.data || []);
  return list.length > 0 ? list[0] : null;
}

// FTC summary — combines vehicles + trip data into one payload
async function ftcSummary(dateFrom, dateTo, env, key, clientMeta) {
  try {
    const companyName = clientMeta?.company || COMPANY;
    // Step 1: get vehicle list (also returns branch names)
    const vehicles = await getVehicleList(env, key, companyName);
    const branches = vehicles._branches || [];

    // Step 2: get driver performance for the period
    let driverPerf = [];
    try { driverPerf = await getDriverPerf(dateFrom, dateTo, env, key, companyName, branches); } catch(e) {}

    // Step 3: enrich each vehicle with trip data and object status
    const enriched = await Promise.all(vehicles.map(async v => {
      // Get live object status FIRST — we need driver name from it for matching
      let status = null;
      if (v.imei) {
        try { status = await getObjectStatus(v.imei, env, key); } catch(e) {}
      }

      // Match driver perf by driver name — use status driver name as it's most reliable
      const statusDriver = String(status?.driver || v.driver_name || "").toLowerCase().trim();
      const perf = driverPerf.find(d => {
        const perfDriver = String(d.driver_name || d.DriverName || "").toLowerCase().trim();
        const perfReg = String(d.Registration || d.registration || "").toLowerCase();
        const vehReg = String(v.registration || "").toLowerCase();
        return (perfDriver && statusDriver && perfDriver === statusDriver) ||
               (perfReg && vehReg && perfReg === vehReg) ||
               String(d.Imei || d.imei || "") === v.imei;
      });

      // Real API fields from driver performance summary:
      // total_running_km, total_running_duration, avg_speed, max_speed, harsh_breaking etc.
      // No fuel field — estimate from km using typical diesel consumption
      const roadKm = parseFloat(perf?.total_running_km || perf?.DistanceKm || perf?.distance_km || perf?.Distance || 0);
      const offroadKm = parseFloat(perf?.OffRoadKm || perf?.off_road_km || 0);

      // Estimate fuel: diesel ~10L/100km for light vehicles, ~12L/100km for heavy
      // Use yesterday_odometer delta if available, otherwise estimate
      const estFuelPer100km = 11; // conservative fleet average
      const fuelLitres = parseFloat(perf?.FuelConsumed || perf?.fuel_consumed || perf?.Fuel || 0) ||
                         (roadKm + offroadKm > 0 ? ((roadKm + offroadKm) * estFuelPer100km / 100) : 0);

      const yesterdayOdom = parseFloat(status?.yesterday_odometer || 0);

      return {
        vehicle_id: v.id,
        registration: v.registration,
        make: v.make,
        model: v.model,
        year: v.year,
        gvm_kg: v.gvm_kg,
        fuel_type: v.fuel_type,
        driver: perf?.driver_name || perf?.DriverName || v.driver_name,
        odometer_start: parseFloat(perf?.OdometerStart || perf?.odometer_start || 0),
        odometer_end: parseFloat(perf?.OdometerEnd || perf?.odometer_end || yesterdayOdom || 0),
        fuel_litres: +fuelLitres.toFixed(1),
        road_km: roadKm,
        offroad_km: offroadKm,
        trips: parseInt(perf?.TripCount || perf?.trip_count || perf?.Trips || 0),
        fuel_estimated: fuelLitres > 0 && !(perf?.FuelConsumed || perf?.fuel_consumed),
        period: new Date(dateFrom).toLocaleDateString("en-AU", { month: "short", year: "numeric" }),
        source: "fleetai",
        _perf: perf,
        _status: status,
      };
    }));

    return corsResponse(JSON.stringify({
      source_endpoint: NETSTAR_BASE + "/external/company-vehicles",
      date_from: dateFrom,
      date_to: dateTo,
      driver_perf_count: driverPerf.length,
      driver_perf_names: driverPerf.map(d => d.driver_name || d.DriverName || "?"),
      vehicles: enriched,
    }), 200);

  } catch (e) {
    return errorResponse("FTC summary failed: " + e.message, 502);
  }
}

// Probe — tests all known real endpoints
async function probe(dateFrom, dateTo, env) {
  const key = getKey(env);
  const from = dateFrom || "2025-04-01";
  const to = dateTo || "2025-04-07";
  const xApiHeaders = { "x-api-key": key, "Accept": "application/json" };
  const bearerHeaders = { "Authorization": "Bearer " + key, "Accept": "application/json" };

  const candidates = [
    // Real UBI endpoints
    { url: UBI_BASE + "/vehicle/vehicles", headers: xApiHeaders },
    { url: UBI_BASE + "/vehicle/vehicles", headers: bearerHeaders },
    { url: UBI_BASE + "/driver/drivers", headers: xApiHeaders },
    // Real FleetAI endpoints
    { url: NETSTAR_BASE + "/external/drivers/driver-performance-summary?company_names=" + COMPANY + "&start_date_time=" + toFleetAIDate(from, false) + "&end_date_time=" + toFleetAIDate(to, true), headers: xApiHeaders },
    { url: NETSTAR_BASE + "/external/reports/object-status?imei=all", headers: xApiHeaders },
    { url: NETSTAR_BASE + "/external/reports/object-status", headers: xApiHeaders },
    // Fallback guesses
    { url: UBI_BASE + "/vehicles", headers: xApiHeaders },
    { url: UBI_BASE + "/api/vehicles", headers: xApiHeaders },
    { url: NETSTAR_BASE + "/external/vehicles", headers: xApiHeaders },
  ];

  const results = await Promise.allSettled(
    candidates.map(async ({ url, headers }) => {
      const res = await fetch(url, { headers });
      let preview = "";
      try { preview = (await res.text()).slice(0, 300); } catch {}
      return { url, auth: headers["x-api-key"] ? "x-api-key" : "bearer", status: res.status, ok: res.ok, preview };
    })
  );

  const report = results.map((r, i) =>
    r.status === "fulfilled" ? r.value : { ...candidates[i], status: "error", ok: false, preview: r.reason?.message }
  );

  return corsResponse(JSON.stringify({
    key_preview: key.slice(0,4) + "***" + key.slice(-4),
    summary: { accessible: report.filter(r => r.ok).length, denied: report.filter(r => r.status === 401 || r.status === 403).length },
    accessible: report.filter(r => r.ok),
    denied: report.filter(r => r.status === 401 || r.status === 403),
    other: report.filter(r => !r.ok && r.status !== 401 && r.status !== 403),
  }, null, 2));
}

