async function handleLogin(request) {
  const body = await request.text();
  const params = new URLSearchParams(body);
  const clientId = params.get("client") || "demo";
  const username = (params.get("username") || "").trim();
  const password = params.get("password") || "";
  const creds = CUSTOMER_CREDENTIALS[clientId];
  if (!creds || username !== creds.username || password !== creds.password) {
    return loginPage(clientId, "Incorrect username or password.");
  }
  const token = makeToken(clientId, username);
  return new Response("", {
    status: 302,
    headers: {
      "Location": `/ftc?client=${clientId}`,
      "Set-Cookie": `ftc_session=${token}; Path=/; HttpOnly; SameSite=Strict; Max-Age=28800`,
    }
  });
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;
    const clientId = (url.searchParams.get("client") || "demo").toLowerCase().trim();
    const clientMeta = getClientMeta(clientId);
    const apiKey = getKey(env, clientId);

    if (request.method === "OPTIONS") return new Response(null, { status: 204, headers: CORS });

    // Login form handler
    if (path === "/ftc-login" && request.method === "POST") return handleLogin(request);

    // Auth check for customer-facing pages
    if (clientId !== "demo" && (path === "/ftc" || path === "/" || path === "/roi")) {
      if (!isAuthenticated(request, clientId)) return loginPage(clientId, "");
    }

    if (path === "/health") {
      return corsResponse(JSON.stringify({ status: "ok", worker: "netstar-proxy", timestamp: new Date().toISOString(), key_preview: getKey(env).slice(0,4) + "***" }));
    }

    if (path === "/roi" || path === "/roi.html") {
      try {
        const res = await fetch("https://raw.githubusercontent.com/bs5jssxhm2-blip/Netstar-proxy/main/roi.html");
        const html = await res.text();
        return new Response(html, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
      } catch(e) { return new Response("Failed to fetch roi.html: " + e.message, { status: 502 }); }
    }

    if (path === "/driver" || path === "/driver.html") {
      try {
        const res = await fetch("https://raw.githubusercontent.com/bs5jssxhm2-blip/Netstar-proxy/main/driver.html");
        const html = await res.text();
        return new Response(html, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
      } catch(e) { return new Response("Failed to fetch driver.html: " + e.message, { status: 502 }); }
    }

    if (path === "/fleet-scores" || path === "/driver-score") {
      try {
        const annualKm = parseInt(url.searchParams.get("annual_km") || "15000");
        let dateFrom = url.searchParams.get("date_from") || url.searchParams.get("start_date") || (() => { const d = new Date(); d.setDate(d.getDate()-7); return d.toISOString().slice(0,10); })();
        const dateTo = url.searchParams.get("date_to") || url.searchParams.get("end_date") || (() => { const d = new Date(); d.setDate(d.getDate()-1); return d.toISOString().slice(0,10); })();
        const imeiFilter = url.searchParams.get("imei") || "";
        const driverFilter = (url.searchParams.get("driver") || url.searchParams.get("driver_name") || "").toLowerCase();

        // Step 1: get vehicle list
        let vlist = await getVehicleList(env, apiKey, clientMeta.company);

        // Step 2: fetch ALL object statuses first, keyed by imei
        const osMap = {};
        await Promise.all(vlist.map(async v => {
          try { const os = await getObjectStatus(v.imei, env, apiKey); if (os) osMap[v.imei] = os; } catch(e) {}
        }));

        // Step 3: enrich vehicle list with real driver names from object status
        vlist = vlist.map(v => Object.assign({}, v, {
          driver_name: osMap[v.imei]?.driver || v.driver_name || "Unknown",
          _matched: false,
        }));

        // For /driver-score with imei: resolve driver name from object status
        let resolvedDriverFilter = driverFilter;
        if (path === "/driver-score" && imeiFilter) {
          const os = osMap[imeiFilter];
          if (os?.driver) resolvedDriverFilter = os.driver.toLowerCase();
        }

        // Step 4: get driver performance — try requested range, fall back to shorter if no data
        // Cap at 60 days max since FleetAI retains ~60 days
        const maxDays = 60;
        const requestedDays = Math.round((new Date(dateTo) - new Date(dateFrom)) / 86400000);
        if (requestedDays > maxDays) {
          dateFrom = new Date(new Date(dateTo) - maxDays * 86400000).toISOString().slice(0, 10);
        }

        let list = await getDriverPerf(dateFrom, dateTo, env, apiKey, clientMeta.company, vlist._branches || []);

        // If no data, try progressively shorter recent windows
        if (!list.length) {
          for (const days of [30, 14, 7]) {
            const fb = new Date(new Date(dateTo) - days * 86400000).toISOString().slice(0, 10);
            list = await getDriverPerf(fb, dateTo, env, apiKey, clientMeta.company, vlist._branches || []);
            if (list.length) { dateFrom = fb; break; }
          }
        }

        if (!list.length) throw new Error("No driver data for this period. Try a date range within the last 30 days.");

        // Step 5: for each perf record, match to vehicle by driver name
        const scored = await Promise.all(list.map(async r => {
          const driverName = r.driver_name || r.driver || "Unknown";
          if (resolvedDriverFilter && resolvedDriverFilter !== driverName.toLowerCase()) return null;

          // Find matching vehicle by driver name
          let mv = null;
          for (let i = 0; i < vlist.length; i++) {
            if ((vlist[i].driver_name || "").toLowerCase() === driverName.toLowerCase() && !vlist[i]._matched) {
              mv = vlist[i]; vlist[i]._matched = true; break;
            }
          }
          // Fallback: first unmatched vehicle
          if (!mv) { for (let j = 0; j < vlist.length; j++) { if (!vlist[j]._matched) { mv = vlist[j]; vlist[j]._matched = true; break; } } }

          const imei = mv ? mv.imei : "";
          const os = osMap[imei] || {};

          // Speed penalty from actual max speed in trip data
          const maxSpd = parseInt(r.max_speed || 0);
          const speedPenalty = maxSpd > 130 ? 20 : maxSpd > 110 ? 10 : maxSpd > 100 ? 5 : 0;

          // Risk score calculation (matches original calcRisk logic)
          const harshBrake = parseInt(r.harsh_breaking || 0);
          const harshAccel = parseInt(r.harsh_acceleration || 0);
          const harshCorn = parseInt(r.harsh_cornering || 0);
          const avgSpd = parseInt(r.avg_speed || 0);
          const avgSpdPenalty = avgSpd > 80 ? 15 : avgSpd > 70 ? 10 : avgSpd > 60 ? 5 : 0;
          const eventScore = (harshBrake * 3) + (harshAccel * 3) + (harshCorn * 2);
          const rawScore = Math.min(100, eventScore + speedPenalty + avgSpdPenalty);
          const riskScore = isNaN(rawScore) ? 50 : Math.round(Math.min(Math.max(rawScore, 0), 100) * 10) / 10;
          const km = parseFloat(r.total_running_km || 0);
          const lc = isNaN(riskScore) ? 0 : Math.round(1200 * (Math.exp(riskScore / 35) - 0.9) * Math.sqrt((km || annualKm) / 15000));
          const rb = riskScore < 20 ? "Excellent" : riskScore < 40 ? "Good" : riskScore < 60 ? "Moderate" : riskScore < 80 ? "High" : "Very High";

          return {
            imei, driver_name: driverName,
            registration: mv?.registration || "", make: mv?.make || "", model: mv?.model || "",
            speed: os.speed || "0", location: os.location || "", status: os.status_hidden || "Unknown",
            risk_score: riskScore, loss_cost: lc, risk_band: rb,
            // Aliases for PAYD scorer renderDetail function
            predicted_loss_cost: lc,
            total_distance_km: km,
            km_driven: km, total_running_km: km,
            avg_speed: avgSpd, max_speed: maxSpd,
            total_running_duration: r.total_running_duration || "0:00",
            running_time: r.total_running_duration || "0:00",
            location_address: os.location || "",
            ignition: os.ignition_status || "Off",
            speed_live: os.speed || "0",
            period_from: dateFrom, period_to: dateTo,
            harsh_breaking: harshBrake, harsh_acceleration: harshAccel, harsh_cornering: harshCorn,
            non_stop_drive: parseInt(r.non_stop_drive || 0),
            night_drive: parseInt(r.night_drive || 0),
            over_speed: parseInt(r.over_speed || 0),
            idling: parseInt(r.idling || 0),
            features: { harsh_breaking: harshBrake, harsh_acceleration: harshAccel, harsh_cornering: harshCorn, max_speed: maxSpd, avg_speed: avgSpd, over_speed: parseInt(r.over_speed||0), night_drive: parseInt(r.night_drive||0), idling: parseInt(r.idling||0) },
          };
        }));

        const results = scored.filter(Boolean);
        if (path === "/driver-score") return corsResponse(JSON.stringify(results[0] || {}));
        return corsResponse(JSON.stringify({ vehicles: results, total: results.length, date_from: dateFrom, date_to: dateTo }));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/live-status") {
      try {
        const vlist = await getVehicleList(env, apiKey, clientMeta.company);
        const statuses = await Promise.all(vlist.map(async v => {
          try { const os = await getObjectStatus(v.imei, env, apiKey); return Object.assign({}, v, { driver_name: os?.driver || v.driver_name || "Unknown", speed: os?.speed || "0", location: os?.location || "", status: os?.status_hidden || "Unknown", coordinates: os?.coordinates || "" }); }
          catch(e) { return v; }
        }));
        return corsResponse(JSON.stringify({ vehicles: statuses, total: statuses.length, updated: new Date().toISOString() }));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/fleetai/perf-probe") {
      const ck = url.searchParams.get("client") || "demo";
      const cm = getClientMeta(ck);
      const ak = getKey(env, ck);
      const from = url.searchParams.get("date_from") || "2026-04-28";
      const to = url.searchParams.get("date_to") || "2026-04-29";
      const loc = url.searchParams.get("location") || "CW - CBS - Building Services";
      const q = new URLSearchParams({
        company_names: cm.company,
        location_names: loc,
        start_date_time: toFleetAIDate(from, false),
        end_date_time: toFleetAIDate(to, true),
      });
      try {
        const res = await fetch(NETSTAR_BASE + "/external/drivers/driver-performance-summary?" + q.toString(), {
          headers: { "x-api-key": ak, "Accept": "application/json" }
        });
        const text = await res.text();
        return corsResponse(JSON.stringify({ status: res.status, query: q.toString(), response: text.slice(0, 2000) }));
      } catch(e) {
        return corsResponse(JSON.stringify({ error: e.message }));
      }
    }

    if (path === "/fleetai/vehicles-probe") {
      const ck = url.searchParams.get("client") || "demo";
      const cm = getClientMeta(ck);
      const ak = getKey(env, ck);
      const body = { company_name: cm.company, company_names: [cm.company] };
      const res = await fetch(NETSTAR_BASE + "/external/company-vehicles", {
        method: "POST",
        headers: { "x-api-key": ak, "Content-Type": "application/json", "Accept": "*/*" },
        body: JSON.stringify(body),
      });
      const text = await res.text();
      return corsResponse(JSON.stringify({ status: res.status, body_sent: body, response: text.slice(0, 2000) }));
    }

    if (path === "/fleetai/probe") {
      return probe(url.searchParams.get("date_from"), url.searchParams.get("date_to"), env);
    }

    if (path === "/fleetai/ftc-summary") {
      const dateFrom = url.searchParams.get("date_from") || url.searchParams.get("from");
      const dateTo = url.searchParams.get("date_to") || url.searchParams.get("to");
      if (!dateFrom || !dateTo) return errorResponse("Missing date_from and date_to (YYYY-MM-DD)", 400);
      return ftcSummary(dateFrom, dateTo, env, apiKey, clientMeta);
    }

    if (path === "/fleetai/vehicles") {
      try {
        const vehicles = await getVehicleList(env, key);
        return corsResponse(JSON.stringify({ vehicles, total: vehicles.length }));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/fleetai/trips") {
      const dateFrom = url.searchParams.get("date_from");
      const dateTo = url.searchParams.get("date_to");
      if (!dateFrom || !dateTo) return errorResponse("Missing date_from / date_to", 400);
      try {
        const data = await getDriverPerf(dateFrom, dateTo, env, apiKey, clientMeta.company);
        return corsResponse(JSON.stringify(data));
      } catch(e) { return errorResponse(e.message, 502); }
    }

    if (path === "/" || path === "/index.html") {
      const rawUrl = env.GITHUB_RAW_URL || "https://raw.githubusercontent.com/bs5jssxhm2-blip/Netstar-proxy/main/index.html";
      try {
        const res = await fetch(rawUrl);
        const html = await res.text();
        return new Response(html, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
      } catch(e) { return new Response("Failed to fetch: " + e.message, { status: 502 }); }
    }

    if (path === "/ftc" || path === "/ftc.html") {
      return new Response(FTC_HTML, { headers: { "Content-Type": "text/html;charset=UTF-8", ...CORS } });
    }

    if (path === "/ai-analysis" && request.method === "POST") {
      try {
        const { prompt } = await request.json();
        if (!prompt) return errorResponse("Missing prompt", 400);
        const res = await fetch("https://api.anthropic.com/v1/messages", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "x-api-key": env.ANTHROPIC_API_KEY || "",
            "anthropic-version": "2023-06-01",
          },
          body: JSON.stringify({ model: "claude-haiku-4-5-20251001", max_tokens: 800, messages: [{ role: "user", content: prompt }] }),
        });
        const data = await res.json();
        if (!res.ok) return errorResponse(data.error?.message || "Anthropic API error", res.status);
        const text = data.content?.filter(b => b.type === "text").map(b => b.text).join("") || "";
        return corsResponse(JSON.stringify({ text }));
      } catch(e) { return errorResponse(e.message, 500); }
    }

    return errorResponse("Unknown route: " + path, 404);
  },
};
